import { createWorkspace, teardownWorkspace } from "@tigrisdata/agent-kit";
import { S3Client, PutObjectCommand } from "@aws-sdk/client-s3";
import { writeFile, readFile, unlink } from "fs/promises";
import { existsSync } from "fs";
import { join } from "path";

const STATE_FILE = "/home/user/pool/pool-state.json";

export interface WorkspaceState {
  name: string;
  bucket: string;
  credentials: {
    accessKeyId: string;
    secretAccessKey: string;
  };
}

export interface PoolState {
  workspaces: WorkspaceState[];
}

export async function provisionPool(n: number): Promise<void> {
  const workspacePromises = [];
  for (let i = 1; i <= n; i++) {
    const name = `pool-${n}-${i}`;
    workspacePromises.push(
      createWorkspace({
        name,
        ttl: { days: 1 },
        credentials: { role: "Editor" },
      })
    );
  }

  const workspaces = await Promise.all(workspacePromises);

  const poolState: PoolState = {
    workspaces: workspaces.map((ws) => ({
      name: ws.name,
      bucket: ws.bucket,
      credentials: {
        accessKeyId: ws.credentials.accessKeyId,
        secretAccessKey: ws.credentials.secretAccessKey,
      },
    })),
  };

  await writeFile(STATE_FILE, JSON.stringify(poolState, null, 2));
}

export async function assignTask(agentIndex: number, text: string): Promise<void> {
  if (!existsSync(STATE_FILE)) {
    throw new Error("pool-state.json is missing");
  }

  const state: PoolState = JSON.parse(await readFile(STATE_FILE, "utf-8"));
  const workspace = state.workspaces[agentIndex - 1];

  if (!workspace) {
    throw new Error(`Agent index ${agentIndex} is out of range`);
  }

  const s3 = new S3Client({
    endpoint: "REDACTED",
    region: "REDACTED",
    credentials: {
      accessKeyId: workspace.credentials.accessKeyId,
      secretAccessKey: workspace.credentials.secretAccessKey,
    },
  });

  await s3.send(
    new PutObjectCommand({
      Bucket: workspace.bucket,
      Key: "task.txt",
      Body: text,
    })
  );
}

export async function status(): Promise<void> {
  if (!existsSync(STATE_FILE)) {
    console.log("pool size: 0");
    return;
  }

  const state: PoolState = JSON.parse(await readFile(STATE_FILE, "utf-8"));
  console.log(`pool size: ${state.workspaces.length}`);
  for (const ws of state.workspaces) {
    console.log(ws.bucket);
  }
}

export async function teardownPool(): Promise<void> {
  if (!existsSync(STATE_FILE)) {
    return;
  }

  const state: PoolState = JSON.parse(await readFile(STATE_FILE, "utf-8"));
  const results = await Promise.allSettled(
    state.workspaces.map((ws) => teardownWorkspace(ws.name))
  );

  await unlink(STATE_FILE);

  const failed = results.some((r) => r.status === "rejected");
  if (failed) {
    throw new Error("One or more teardown operations failed");
  }
}

import { provisionPool, assignTask, status, teardownPool } from "./manager.js";

async function main() {
  const [subcommand, ...args] = process.argv.slice(2);

  try {
    switch (subcommand) {
      case "provision": {
        const n = parseInt(args[0], 10);
        if (isNaN(n)) {
          throw new Error("Usage: provision <N>");
        }
        await provisionPool(n);
        break;
      }
      case "assign-task": {
        const index = parseInt(args[0], 10);
        const text = args[1];
        if (isNaN(index) || text === undefined) {
          throw new Error("Usage: assign-task <agent-index> <text>");
        }
        await assignTask(index, text);
        break;
      }
      case "status": {
        await status();
        break;
      }
      case "teardown": {
        await teardownPool();
        break;
      }
      default:
        console.error("Unknown subcommand. Supported subcommands: provision, assign-task, status, teardown");
        process.exit(1);
    }
  } catch (error: any) {
    console.error(error.message);
    process.exit(1);
  }
}

main();

